import React from "react";

export default function Hourly({ data = [] }) {
  const slice = Array.isArray(data) ? data.slice(0, 24) : [];

  return (
    <div className="w-full">
      <div className="flex gap-2 overflow-x-auto no-scrollbar">
        {slice.map((h, i) => {
          const dt = h?.dt ? new Date(h.dt * 1000) : new Date(Date.now() + i * 3600000);
          const hour = dt.toLocaleTimeString([], { hour: "numeric" });
          const temp = h?.temp != null ? Math.round(h.temp) : "—";
          const icon = h?.weather?.[0]?.icon || "⛅";

          return (
            <div
              key={i}
              className="shrink-0 w-20 rounded-2xl bg-white/20 backdrop-blur border border-white/20 px-3 py-3 text-center"
            >
              <div className="text-xs opacity-70">{hour}</div>
              <div className="text-lg my-1">{icon}</div>
              <div className="text-sm font-medium">{temp}°</div>
            </div>
          );
        })}
      </div>
    </div>
  );
}
